INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-814ced5a-moex-00006', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', 'RDA 以 FRBR 家族概念模型為基礎發展，以描述各種不同內容與類型的資源。有關 RDA 內容之敘 述，下列何者錯誤？', '["RDA整體內容應包括資源著錄、關係與檢索點控制三個部分", "資源著錄係指書目資料的建立，包括資源描述的功能性目標及原則", "關係係指書目資料主要款目的建立，包括有關的個人、家族、團體、相關作品及特定類型作品等", "檢索點控制係指書目紀錄與權威紀錄之間的關係建立，為建構檢索點及記載檢索點控制的相關資料"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00007', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '下列敘述，何者與《中國編目規則》第三版的條文規定相符？', '["為求著錄一致化，著錄需有依據，各館應考量讀者需求與館藏特色，自行擇定圖書資料之著錄來源", "若著錄來源中之題名或著者有誤，應設法考證，並依查得之正確內容著錄於題名及著者敘述項", "凡書名頁或版權頁中載有與正題名不同語文之其他題名，一律以並列題名著錄", "書目資料之著錄，依其詳簡分為簡略、標準及詳細三個層次，各館可視需要採用適當之著錄層次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00008', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '依據《中國編目規則》第三版，有關題名檢索款目之敘述，下列何者錯誤？', '["非載於主要著錄來源而與正題名有重要差異之題名，得立為檢索款目", "集叢之各單元分別編目時，得將集叢名立為檢索款目", "劃一題名得立為檢索款目", "改寫作品之原題名不得作為檢索款目"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00009', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '依照《中國編目規則》第三版相關規定建置書目紀錄，下列有關連續性出版品題名處理方式之敘述， 何者正確？', '["若正題名包含前刊名，前刊名應著錄於正題名之後", "若主要著錄來源載有全名及縮寫，以全名著錄為正題名", "若正題名包括逢期更動的日期或編號，應予以照錄", "正題名若有更易，應將更易後之題名視為正題名，原題名著錄於附註項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00010', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '團體名稱若前後有所變更，新舊不同名稱間，應以何方式建立關聯？', '["不用", "見", "反見", "參見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00011', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '若出版者名稱已載於題名及著者敘述項時，依據《中國編目規則》第三版出版者應如何著錄？', '["出版者全稱或出版者簡稱皆可", "一律採用出版者全稱", "一律採用出版者簡稱", "以「著者」、「編著」、「該部」、「該館」、「該會」等取代出版者名稱"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00012', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '關於國際標準書目著錄（InternationalStandardBibliographicDescription,ISBD）之敘述，下列何者 正確？', '["ISBD並非各國擬訂編目規則的依據", "研訂ISBD的目標是為國際圖書館界提供名稱權威的著錄標準", "有關內容形式和媒體型態項，ISBD以新增的第1段（Area1）表示", "ISBD的目的在使不同機構著錄的書目紀錄可以跨語言與資料類型達成書目共享"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00013', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '國際編目原則（Statement of International Cataloguing Principles, ICP）的一般原則中「表達性」 （representation）強調的要項是什麼？', '["適合一般的使用", "儘可能按照資源單件所出現的資料照樣著錄", "使用者不會因為不瞭解的用詞或縮寫字而產生困惑", "儘可能地對所有類型資源或其他實體採用一套共用的原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00014', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '《資源描述與檢索》（RDA）附錄I的關係標示用語中，下列何者屬於貢獻者的關係用語？', '["編輯（editor）", "文字作者（author）", "雕塑家（sculptor）", "建築師（architect）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00015', 'locality-814ced5a', 'locality-814ced5a-moex-111-e97233f0', 'sub-locality-814ced5a-01', NULL, 'single_choice', '《紅樓夢》，又名《石頭記》，作者本名曹霑，字夢阮，號雪芹，依據《資源描述與檢索》（RDA）著錄', '["以曹霑為首選人名", "以曹雪芹為首選人名", "以紅樓夢為首選題名", "以石頭記為首選題名"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "61714e786226", "answer_pdf_sha1": "dc6e5e39a49c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0416", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中文圖書分類編目大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
